import ExpenseItem from './ExpenseItem'

function Items(props) {
    return (<div>
        <ExpenseItem
            title={Items.props[0].title}
            amount={Items.props[0].amount}
            date={Items.props[0].date}
        />
        <ExpenseItem
            title={Items.props[1].title}
            amount={Items.props[1].amount}
            date={Items.props[1].date}
        ></ExpenseItem>
        <ExpenseItem
            title={Items.props[2].title}
            amount={Items.props[2].amount}
            date={Items.props[2].date}
        />
        <ExpenseItem
            title={Items.props[3].title}
            amount={Items.props[3].amount}
            date={Items.props[3].date}
        />
    </div>
    )
}
